INSERT INTO sock VALUES ("c2000040-0000-4000-a000-000000000040", "Raspberry Pi Pico W - Dual-Core 133MHz WiFi", "The wireless version of the RP2040. Features dual-core Cortex M0+ at 133MHz, 2MB Flash, 264KB SRAM, and an on-board Infineon CYW43439 chip providing 2.4GHz WiFi and Bluetooth 5.2. Perfect for low-power IoT applications.", 7.00, 500, "/catalogue/images/rpi-pico.jpg", "/catalogue/images/rpi-pico-2.jpg");
INSERT INTO sock VALUES ("c2000041-0000-4000-a000-000000000041", "STM32F401 Black Pill - High Speed 84MHz MCU", "High-performance ARM Cortex-M4 at 84MHz with 256KB Flash and 64KB RAM. Offers a significant speed boost over the Blue Pill, featuring native USB Type-C and a reliable hardware design for industrial prototyping.", 6.50, 200, "/catalogue/images/stm32-nucleo.jpg", "/catalogue/images/stm32-nucleo-2.jpg");
INSERT INTO sock VALUES ("c2000042-0000-4000-a000-000000000042", "Teensy 4.0 - 600MHz ARM Cortex-M7", "One of the fastest microcontrollers available. Features an ARM Cortex-M7 at 600MHz, 1MB RAM, and 2MB Flash. Ideal for high-speed digital signal processing and complex robotics calculations in a tiny form factor.", 25.00, 50, "/catalogue/images/arduino-mega.jpg", "/catalogue/images/arduino-mega-2.jpg");
INSERT INTO sock VALUES ("c2000043-0000-4000-a000-000000000043", "ESP32-S2 Saola-1 - Native USB IoT Board", "Single-core 240MHz Xtensa LX7 with 4MB Flash and 2MB PSRAM. Features 43 GPIOs and native USB support, designed for security-focused IoT applications and low-power operations.", 9.00, 150, "/catalogue/images/esp32-devboard.jpg", "/catalogue/images/esp32-devboard-2.jpg");
INSERT INTO sock VALUES ("c2000044-0000-4000-a000-000000000044", "Arduino GIGA R1 WiFi - Dual-Core Powerhouse", "Powered by a dual-core STM32H7 (M7 at 480MHz & M4 at 240MHz). Features 76 GPIO pins, 12-bit DAC, and integrated WiFi/BT. Designed for high-end automation and multimedia projects.", 75.00, 30, "/catalogue/images/arduino-mega-2.jpg", "/catalogue/images/arduino-mega.jpg");
INSERT INTO sock VALUES ("c2000045-0000-4000-a000-000000000045", "Raspberry Pi Zero 2 W - Quad-Core 1GHz", "The successor to the Zero W, featuring a quad-core 64-bit ARM Cortex-A53 CPU and 512MB SDRAM. Up to five times faster than the original while maintaining the same ultra-small form factor.", 16.00, 100, "/catalogue/images/rpi-pico.jpg", "/catalogue/images/rpi-pico-2.jpg");
INSERT INTO sock VALUES ("c2000046-0000-4000-a000-000000000046", "Orange Pi 5 - RK3588S 8-Core 8GB RAM", "Utilizes the Rockchip RK3588S 8-core 64-bit processor (4x A76, 4x A55) with 8GB LPDDR4X RAM. Supports 8K video output and features a 6 TOPS NPU for on-device AI acceleration.", 115.00, 40, "/catalogue/images/rpi4b.jpg", "/catalogue/images/rpi4b-2.jpg");
INSERT INTO sock VALUES ("c2000047-0000-4000-a000-000000000047", "Libre Renegade - ROC-RK3328-CC 2GB", "A powerful alternative to the Pi 3 with USB 3.0 and Gigabit Ethernet. Quad-core 64-bit CPU and 2GB DDR4 RAM. Excellent Linux support for server or media applications.", 48.00, 60, "/catalogue/images/rpi4b-2.jpg", "/catalogue/images/rpi4b.jpg");
INSERT INTO sock VALUES ("c2000048-0000-4000-a000-000000000048", "Rock 5B - RK3588 High-Performance SBC", "High-end SBC with support for up to 16GB RAM, dual 4K HDMI ports, and 2.5G Ethernet. Designed for server-grade workloads and heavy edge computing environments.", 145.00, 20, "/catalogue/images/beaglebone-black.jpg", "/catalogue/images/beaglebone-black-2.jpg");
INSERT INTO sock VALUES ("c2000049-0000-4000-a000-000000000049", "Jetson Orin Nano Developer Kit 8GB", "NVIDIA Ampere architecture with 1024-core GPU. Delivers up to 40 TOPS for AI performance. The leading choice for robotics engineers and edge AI development.", 495.00, 15, "/catalogue/images/jetson-nano.jpg", "/catalogue/images/jetson-nano-2.jpg");
INSERT INTO sock VALUES ("c2000050-0000-4000-a000-000000000050", "AHT20 + BMP280 Precision Climate Sensor", "A dual-sensor module for high-precision temperature, humidity, and barometric pressure. Uses I2C and is significantly more stable and accurate than older DHT-series sensors.", 5.50, 300, "/catalogue/images/esp32-devboard.jpg", "/catalogue/images/esp32-devboard-2.jpg");
INSERT INTO sock VALUES ("c2000051-0000-4000-a000-000000000051", "SCD41 True CO2 Photoacoustic Sensor", "High-precision CO2 sensor with integrated temperature and humidity. Provides laboratory-grade air quality data (400–5000 ppm range) via I2C interface.", 38.00, 50, "/catalogue/images/arduino-uno.jpg", "/catalogue/images/arduino-uno-2.jpg");
INSERT INTO sock VALUES ("c2000052-0000-4000-a000-000000000052", "TFMini-S LiDAR Distance Module 12m", "Compact single-point ToF LiDAR. Measures distances up to 12m with a high frame rate of 1000Hz. Perfect for drone altitude hold and robotic obstacle avoidance.", 42.00, 80, "/catalogue/images/stm32-nucleo-2.jpg", "/catalogue/images/stm32-nucleo.jpg");
INSERT INTO sock VALUES ("c2000053-0000-4000-a000-000000000053", "MAX30102 Heart-Rate & Oximeter Sensor", "Integrated pulse oximetry and heart-rate monitor biosensor. Combines LEDs, photodetector, and low-noise electronics with ambient light rejection for wearable tech.", 4.20, 250, "/catalogue/images/esp32-devboard-2.jpg", "/catalogue/images/esp32-devboard.jpg");
INSERT INTO sock VALUES ("c2000054-0000-4000-a000-000000000054", "AS5600 12-Bit Magnetic Rotary Encoder", "Contactless rotary position sensor with 12-bit resolution. I2C or analog output. Ideal for high-precision knobs and closed-loop motor control in robotics.", 3.80, 400, "/catalogue/images/arduino-uno-2.jpg", "/catalogue/images/arduino-uno.jpg");
INSERT INTO sock VALUES ("c2000055-0000-4000-a000-000000000055", "RA-02 LoRa SX1278 433MHz Long-Range", "Spread spectrum communication module capable of multi-kilometer range. Operates on 433MHz with high interference immunity. SPI interface, 3.3V logic.", 6.50, 150, "/catalogue/images/stm32-nucleo.jpg", "/catalogue/images/stm32-nucleo-2.jpg");
INSERT INTO sock VALUES ("c2000056-0000-4000-a000-000000000056", "SIM7600G-H Global 4G/LTE/GPS Module", "Global 4G/LTE Cat-4 communication module with GNSS. Supports high-speed data and African cellular bands. Perfect for remote tracking and IoT gateways.", 65.00, 40, "/catalogue/images/arduino-mega.jpg", "/catalogue/images/arduino-mega-2.jpg");
INSERT INTO sock VALUES ("c2000057-0000-4000-a000-000000000057", "HC-12 433MHz UART Wireless Transceiver", "Transparent serial wireless module with up to 1km range. Operates on 100 channels in the 433.4-473.0MHz range. Simple UART 'plug and play' interface.", 5.00, 300, "/catalogue/images/esp32-devboard.jpg", "/catalogue/images/esp32-devboard-2.jpg");
INSERT INTO sock VALUES ("c2000058-0000-4000-a000-000000000058", "RYLR896 LoRa AT-Command Module", "Features a built-in MCU handling the LoRa stack. Controlled via simple AT commands over UART. Simplifies long-range wireless without complex SPI coding.", 12.00, 100, "/catalogue/images/arduino-uno.jpg", "/catalogue/images/arduino-uno-2.jpg");
INSERT INTO sock VALUES ("c2000059-0000-4000-a000-000000000059", "nRF52840 BLE 5.0 / Thread USB Dongle", "Advanced multiprotocol Bluetooth 5 / Thread / Zigbee / ANT / 2.4GHz SoC. Native USB support for PC-to-sensor communication and sniffer applications.", 14.00, 75, "/catalogue/images/stm32-nucleo-2.jpg", "/catalogue/images/stm32-nucleo.jpg");
INSERT INTO sock VALUES ("c2000060-0000-4000-a000-000000000060", "MG90S Metal Gear Micro Servo 2.2kg/cm", "Upgraded version of the SG90 with full metal gears. Provides 2.2kg/cm torque. Durable choice for robotic grippers and steering systems.", 3.50, 400, "/catalogue/images/arduino-uno-2.jpg", "/catalogue/images/arduino-uno.jpg");
INSERT INTO sock VALUES ("c2000061-0000-4000-a000-000000000061", "DS3218 20kg High-Torque Digital Servo", "Heavy-duty, waterproof digital servo with stainless steel gears. Delivers 20kg of torque at 6.8V. Designed for large-scale robotics and RC vehicles.", 18.00, 60, "/catalogue/images/arduino-mega.jpg", "/catalogue/images/arduino-mega-2.jpg");
INSERT INTO sock VALUES ("c2000062-0000-4000-a000-000000000062", "TB6612FNG Dual DC Motor Driver 1.2A", "High-efficiency MOSFET driver (superior to L298N). Controls 2 DC motors at 1.2A. Features standby mode and thermal protection for mobile robots.", 4.50, 200, "/catalogue/images/arduino-mega-2.jpg", "/catalogue/images/arduino-mega.jpg");
INSERT INTO sock VALUES ("c2000063-0000-4000-a000-000000000063", "PCA9685 16-Channel 12-Bit PWM I2C Driver", "Allows controlling up to 16 servos using only 2 pins via I2C. Essential for multi-legged robots (hexapods) and complex bionic systems.", 5.50, 150, "/catalogue/images/stm32-nucleo-2.jpg", "/catalogue/images/stm32-nucleo.jpg");
INSERT INTO sock VALUES ("c2000064-0000-4000-a000-000000000064", "DRV8825 High-Current Stepper Driver 2.2A", "Supports 1/32 microstepping for ultra-smooth motion. Drives up to 2.2A per coil. Includes adjustable current limit and thermal shutdown.", 3.80, 300, "/catalogue/images/arduino-uno.jpg", "/catalogue/images/arduino-uno-2.jpg");
INSERT INTO sock VALUES ("c2000065-0000-4000-a000-000000000065", "TS101 Smart Digital Soldering Iron PD/DC", "Programmable digital iron with OLED screen. Powered via USB-C (PD) or DC jack. Features rapid heat-up and precise temperature stability.", 65.00, 30, "/catalogue/images/arduino-mega.jpg", "/catalogue/images/arduino-mega-2.jpg");
INSERT INTO sock VALUES ("c2000066-0000-4000-a000-000000000066", "Bus Pirate v3.6 - Universal Serial Debugger", "An open-source interface that talks to chips via I2C, SPI, and UART. Saves time by testing hardware commands before writing any firmware.", 32.00, 25, "/catalogue/images/arduino-uno-2.jpg", "/catalogue/images/arduino-uno.jpg");
INSERT INTO sock VALUES ("c2000067-0000-4000-a000-000000000067", "Logic Analyzer 24MHz 8-Channel USB", "Essential for debugging timing issues. Visualizes digital signals on your PC. Decodes SPI, I2C, UART and more via Sigrok/PulseView software.", 12.00, 80, "/catalogue/images/arduino-mega-2.jpg", "/catalogue/images/arduino-mega.jpg");
INSERT INTO sock VALUES ("c2000068-0000-4000-a000-000000000068", "FNIRSI-138 Pro Handheld Digital Oscilloscope", "A portable, battery-powered 2.4-inch oscilloscope. 200KHz bandwidth and 2.5MS/s sample rate. Perfect for field testing sensor waveforms.", 28.00, 40, "/catalogue/images/esp32-devboard-2.jpg", "/catalogue/images/esp32-devboard.jpg");
INSERT INTO sock VALUES ("c2000069-0000-4000-a000-000000000069", "Precision Anti-Static Tweezers - 6 Piece Set", "High-quality ESD-safe tweezers for handling SMD components and fine wiring. Essential for professional electronics assembly and repair.", 8.50, 100, "/catalogue/images/arduino-uno.jpg", "/catalogue/images/arduino-uno-2.jpg");
